<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    color: #eee;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    overflow: hidden;
  }
  .container { text-align: center; }
  canvas {
    border: 2px solid #333;
    cursor: crosshair;
    background: #0f0f23;
    display: block;
    margin: 0 auto;
  }
  .controls {
    margin-top: 15px;
    display: flex;
    justify-content: center;
    gap: 8px;
    flex-wrap: wrap;
  }
  button {
    padding: 10px 20px;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-size: 14px;
    font-weight: 500;
    transition: all 0.15s ease;
    color: #333;
  }
  button:hover { transform: translateY(-2px); filter: brightness(1.1); }
  button.active { outline: 3px solid white; box-shadow: 0 0 10px rgba(255,255,255,0.3); }
  #mat-sand    { background: #e6c85a; }
  #mat-water   { background: #4fc3f7; }
  #mat-wall    { background: #9e9e9e; }
  #mat-acid    { background: #ff5252; color: white; }
  #mat-empty   { background: #444; color: #eee; border: 1px solid #666; }
  #clear       { background: #f44336; color: white; margin-left: auto; }
</style>
</head>
<body>
<div class="container">
  <canvas id="sand" width="600" height="600"></canvas>
  <div class="controls">
    <button id="mat-sand">Sand</button>
    <button id="mat-water">Water</button>
    <button id="mat-wall">Wall</button>
    <button id="mat-acid">Acid</button>
    <button id="mat-empty">Eraser</button>
    <button id="clear">Clear All</button>
  </div>
</div>

<script>
// === Configuration ===
const W = 120, H = 120; // grid size (≥80×80)
let grid = [];

const EMPTY = 0, SAND = 1, WATER = 2, WALL = 3, ACID = 4;
const MATERIALS = ['empty', 'sand', 'water', 'wall', 'acid'];

const MAT_TO_BTN = {
  [EMPTY]: 'mat-empty',
  [SAND]: 'mat-sand',
  [WATER]: 'mat-water',
  [WALL]: 'mat-wall',
  [ACID]: 'mat-acid'
};

// === Grid helpers ===
function initGrid() {
  grid = Array.from({length: H}, () => new Uint8Array(W));
}

function getMaterial(x, y) {
  if (x < 0 || x >= W || y < 0 || y >= H) return EMPTY;
  return grid[y][x];
}

function setMaterial(x, y, mat) {
  if (x >= 0 && x < W && y >= 0 && y < H) {
    grid[y][x] = mat;
  }
}

// === Simulation tick (bottom-up, one cell per step) ===
function tick() {
  for (let y = H - 2; y >= 0; y--) {
    for (let x = 0; x < W; x++) {
      const c = grid[y][x];
      if (c === SAND) processSand(x, y);
      else if (c === WATER || c === ACID) processLiquid(c, x, y);
    }
  }
}

function processSand(x, y) {
  // fall straight down — swap with water/acid below
  const b = getMaterial(x, y + 1);
  if (b === EMPTY || b === WATER || b === ACID) {
    setMaterial(x, y, b);
    setMaterial(x, y + 1, SAND);
    return;
  }

  // blocked below → slide diagonal (randomize checked direction first)
  const dir = Math.random() < 0.5 ? -1 : 1;
  const nx1 = x + dir;
  if (nx1 >= 0 && nx1 < W) {
    const d1 = getMaterial(nx1, y + 1);
    if (d1 === EMPTY || d1 === WATER || d1 === ACID) {
      setMaterial(x, y, d1);
      setMaterial(nx1, y + 1, SAND);
      return;
    }
  }
  const nx2 = x - dir;
  if (nx2 >= 0 && nx2 < W) {
    const d2 = getMaterial(nx2, y + 1);
    if (d2 === EMPTY || d2 === WATER || d2 === ACID) {
      setMaterial(x, y, d2);
      setMaterial(nx2, y + 1, SAND);
      return;
    }
  }
}

function processLiquid(type, x, y) {
  const isAcid = type === ACID;

  // fall straight down — swap with water/acid below
  const b = getMaterial(x, y + 1);
  if (b === EMPTY || b === WATER || b === ACID) {
    setMaterial(x, y, b);
    setMaterial(x, y + 1, type);
    return;
  }

  // blocked below → spread horizontally (randomize direction first)
  const dir = Math.random() < 0.5 ? -1 : 1;
  const nx1 = x + dir;
  if (nx1 >= 0 && nx1 < W) {
    const s1 = getMaterial(nx1, y);
    if (s1 === EMPTY || s1 === WATER || s1 === ACID) {
      setMaterial(x, y, s1);
      setMaterial(nx1, y, type);
      return;
    }
  }
  const nx2 = x - dir;
  if (nx2 >= 0 && nx2 < W) {
    const s2 = getMaterial(nx2, y);
    if (s2 === EMPTY || s2 === WATER || s2 === ACID) {
      setMaterial(x, y, s2);
      setMaterial(nx2, y, type);
      return;
    }
  }

  // acid dissolves sand/wall below or beside
  if (isAcid) dissolve(x, y);
}

function dissolve(x, y) {
  const b = getMaterial(x, y + 1);
  if (b === SAND || b === WALL) setMaterial(x, y + 1, EMPTY);

  for (const dx of [-1, 1]) {
    const nx = x + dx;
    if (nx >= 0 && nx < W) {
      const s = getMaterial(nx, y);
      if (s === SAND || s === WALL) setMaterial(nx, y, EMPTY);
    }
  }
}

// === Rendering ===
const canvas = document.getElementById('sand');
const ctx = canvas.getContext('2d');

function draw() {
  ctx.fillStyle = '#0f0f23';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  const cw = canvas.width / W;
  const ch = canvas.height / H;

  for (let y = 0; y < H; y++) {
    for (let x = 0; x < W; x++) {
      const m = grid[y][x];
      if (m === EMPTY) continue;
      ctx.beginPath();
      ctx.arc(x * cw + cw / 2, y * ch + ch / 2, Math.min(cw, ch) / 2 - 0.5, 0, Math.PI * 2);
      switch (m) {
        case SAND:    ctx.fillStyle = '#e6c85a'; break;
        case WATER:   ctx.fillStyle = '#4fc3f7'; break;
        case WALL:    ctx.fillStyle = '#9e9e9e'; break;
        case ACID:    ctx.fillStyle = '#ff5252'; break;
      }
      ctx.fill();
    }
  }
}

// === Mouse painting ===
let isPainting = false, currentMaterial = SAND;

canvas.addEventListener('mousedown', e => { isPainting = true; paintAt(e); });
canvas.addEventListener('mousemove', e => { if (!isPainting) return; paintAt(e); });
window.addEventListener('mouseup', () => { isPainting = false; });

function paintAt(e) {
  const rect = canvas.getBoundingClientRect();
  const sx = W / rect.width, sy = H / rect.height;
  const x = Math.floor((e.clientX - rect.left) * sx);
  const y = Math.floor((e.clientY - rect.top) * sy);
  if (x >= 0 && x < W && y >= 0 && y < H) {
    setMaterial(x, y, currentMaterial);
    draw();
  }
}

// === UI controls ===
function updateButtons() {
  document.querySelectorAll('.controls button').forEach(b => b.classList.remove('active'));
  const id = MAT_TO_BTN[currentMaterial];
  if (id) document.getElementById(id).classList.add('active');
}

document.getElementById('mat-sand').addEventListener('click', () => { currentMaterial = SAND; updateButtons(); });
document.getElementById('mat-water').addEventListener('click', () => { currentMaterial = WATER; updateButtons(); });
document.getElementById('mat-wall').addEventListener('click', () => { currentMaterial = WALL; updateButtons(); });
document.getElementById('mat-acid').addEventListener('click', () => { currentMaterial = ACID; updateButtons(); });
document.getElementById('mat-empty').addEventListener('click', () => { currentMaterial = EMPTY; updateButtons(); });

document.getElementById('clear').addEventListener('click', () => { initGrid(); draw(); });

// === Animation loop ===
function animate() { tick(); draw(); requestAnimationFrame(animate); }

// === Init & expose API ===
initGrid();
draw();
animate();

window.sim = {
  w: W,
  h: H,
  tick(n)   { for (let i = 0; i < n; i++) tick(); },
  get(x, y) { return MATERIALS[getMaterial(x, y)]; },
  set(x, y, mat) { const idx = MATERIALS.indexOf(mat); if (idx >= 0) setMaterial(x, y, idx); },
  clear()     { initGrid(); draw(); }
};
</script>
</body>
</html>
